diagramaBajoNivel:
graph TD
    START([START]) --> A(Copiar y renombrar archivo sistema);
    A --> B{¿Archivo copiado?};
    B -- No --> E1(Log error copia y salir) --> END;
    B -- Si --> C(Acceder SAP MCL5 - Venta Historica);
    C --> D(Completar centro y mov. 601 - Venta Historica);
    D --> D1{¿Fechas validas?};
    D1 -- No --> E2(Log error fecha y salir) --> END;
    D1 -- Si --> E(Desglosar por material - Venta Historica);
    E --> F(Exportar TXT Venta Historica);
    F --> G(Acceder SAP MCL5 - Venta Ultimo Mes);
    G --> H(Completar centro y mov. 601 - Venta Ultimo Mes);
    H --> H1{¿Fechas validas?};
    H1 -- No --> E2 --> END;
    H1 -- Si --> I(Desglosar por material - Venta Ultimo Mes);
    I --> J(Exportar TXT Venta Ultimo Mes);
    J --> K(Acceder SAP LX29 - Stock);
    K --> L(Completar almacen TIC y centro - Stock);
    L --> M(Exportar TXT Stock);
    M --> N(Acceder SAP MCL5 - Reposiciones);
    N --> O(Completar centro, mov. 919-920 - Reposiciones);
    O --> O1{¿Fechas validas?};
    O1 -- No --> E2 --> END;
    O1 -- Si --> P(Desglosar por material - Reposiciones);
    P --> Q(Exportar TXT Reposiciones);
    Q --> R(Acceder a disco compartido - Archivo Tipo Ubicacion);
    R --> R1{¿Permisos de acceso?};
    R1 -- No --> E3(Log error permisos y salir) --> END;
    R1 -- Si --> S(Copiar archivo Tipo Ubicacion);
    S --> S1{¿Archivo Tipo Ubicacion valido?};
    S1 -- No --> E4(Log error archivo invalido y salir) --> END;
    S1 -- Si --> T(Abrir archivo mapa de calor XLSX);
    T --> U(Presionar Actualizar todo en Datos);
    U --> V(Ejecutar macro Generar Intercambios);
    V --> W(Ingresar parametros - 0, 0, estante alto);
    W --> X(Verificar hoja intercambios generada);
    X --> END([END]);
